changeSet.createView:
SELECT /* ── Identification du compte ────────────────────────────── */ cpt.planComptable AS num_compte, cpt.agence AS code_agence, ag.NOMAGENCE AS nom_agence,
/* ── Cumuls ──────────────────────────────────────────────── */ COUNT(*) AS nb_ecritures, COALESCE(SUM(cpt.DEBIT), 0) AS total_debit, COALESCE(SUM(cpt.CREDIT), 0) AS total_credit,
/* ── Soldes ──────────────────────────────────────────────── */ COALESCE(SUM(cpt.DEBIT), 0) - COALESCE(SUM(cpt.CREDIT), 0) AS solde_net,
CASE WHEN COALESCE(SUM(cpt.DEBIT), 0) > COALESCE(SUM(cpt.CREDIT), 0) THEN COALESCE(SUM(cpt.DEBIT), 0) - COALESCE(SUM(cpt.CREDIT), 0) ELSE 0 END AS solde_debiteur,
CASE WHEN COALESCE(SUM(cpt.CREDIT), 0) > COALESCE(SUM(cpt.DEBIT), 0) THEN COALESCE(SUM(cpt.CREDIT), 0) - COALESCE(SUM(cpt.DEBIT), 0) ELSE 0 END AS solde_crediteur,
/* ── Fenêtre temporelle ──────────────────────────────────── */ MIN(cpt.DATEOPERATION) AS date_premiere_ecriture, MAX(cpt.DATEOPERATION) AS date_derniere_ecriture
FROM comptabilite cpt
LEFT JOIN AGENCE ag ON ag.CODE_AGENCE = cpt.agence
WHERE cpt.planComptable IS NOT NULL
GROUP BY cpt.planComptable, cpt.agence, ag.NOMAGENCE
